Part.Source:
RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon031_TipoLctoBalanco, &TCon031_TipoLctoBalanco)
&LctCod = iif(&TCon031_TipoLctoBalanco.IsEmpty(), 0, Val(&TCon031_TipoLctoBalanco))

&PedCod.SetEmpty()

//LOCaliza Balanco feito Data de Hoje
//balanco Automatico
For Each Order EmpCod, FilCod, BalCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where BalFunCod = -1
	Where BalObs = 'AJUSTE ESTOQUE / IMPORTACAO / PRODUTOS'
	Where BalDta = serverdate()
	Where BalSts = Status_Pedido.ABERTO
	Where BalTip = TipoBalanco.Gerencial
	&BalCod = BalCod
	&PedCod = BalPedCod

	Exit
EndFor

if &BalCod.IsEmpty()
	UltimoCodigoEmpresa.Call(domParCod.BALANCO, &EmpCod, &FilCod, &BalCod)

	//gravaBalanco
	New
		EmpCod = &EmpCod
		BalCod = &BalCod
		FilCod = &FilCod
		BalFunCod = -1
		BalDta = serverdate()
		BalObs = 'AJUSTE ESTOQUE / IMPORTACAO / PRODUTOS'
		BalSts = Status_Pedido.ABERTO
		BalStsPrc = AtualizandoEstoquePedido.Aberto
		BalTip = TipoBalanco.Gerencial
		BalPedCod = 0
	EndNew	
	Commit

	//Grava item Balanco
	GravaProdutoBalanco.Call(&EmpCod, &FilCod, &BalCod, &ProCod, &ProGraCod, &BalQtd, &InseridoMensagem, &AtualizadoMensagem)
Else	
	//Grava item Balanco
	GravaProdutoBalanco.Call(&EmpCod, &FilCod, &BalCod, &ProCod, &ProGraCod, &BalQtd, &InseridoMensagem, &AtualizadoMensagem)
EndiF

